const RATE_LIMIT_WINDOW = 60000; // 1 minute
const MAX_REQUESTS_PER_WINDOW = 10;

class APIIntegrationWorker {
  constructor(env) {
    this.env = env;
    this.sendgridApiKey = env.SENDGRID_API_KEY;
    this.stripeApiKey = env.STRIPE_API_KEY;
    this.allowedOrigins = (env.ALLOWED_ORIGINS || '').split(',').filter(Boolean);
    this.apiSecretKey = env.API_SECRET_KEY;
  }

  async handleRequest(request) {
    try {
      if (request.method === 'OPTIONS') {
        return this.handleCORS(request);
      }

      if (!this.validateOrigin(request)) {
        return this.errorResponse('Invalid origin', 403);
      }

      const rateLimitResult = await this.checkRateLimit(request);
      if (!rateLimitResult.allowed) {
        return this.errorResponse('Rate limit exceeded', 429, {
          'Retry-After': '60',
          'X-RateLimit-Limit': MAX_REQUESTS_PER_WINDOW.toString(),
          'X-RateLimit-Remaining': '0'
        });
      }

      const authResult = this.authenticateRequest(request);
      if (!authResult.valid) {
        return this.errorResponse('Unauthorized', 401);
      }

      const url = new URL(request.url);
      const path = url.pathname;

      if (path === '/api/send-email' && request.method === 'POST') {
        return await this.handleSendEmail(request);
      } else if (path === '/api/create-payment-intent' && request.method === 'POST') {
        return await this.handleCreatePaymentIntent(request);
      } else if (path === '/api/webhook/stripe' && request.method === 'POST') {
        return await this.handleStripeWebhook(request);
      } else if (path === '/health' && request.method === 'GET') {
        return this.jsonResponse({ status: 'healthy', timestamp: Date.now() });
      } else {
        return this.errorResponse('Not found', 404);
      }
    } catch (error) {
      console.error('Unhandled error:', error);
      return this.errorResponse('Internal server error', 500);
    }
  }

  validateOrigin(request) {
    if (this.allowedOrigins.length === 0) return true;
    
    const origin = request.headers.get('Origin');
    if (!origin) return false;
    
    return this.allowedOrigins.some(allowed => {
      if (allowed === '*') return true;
      return origin === allowed || origin.endsWith('.' + allowed);
    });
  }

  async checkRateLimit(request) {
    if (!this.env.RATE_LIMIT) {
      return { allowed: true, remaining: MAX_REQUESTS_PER_WINDOW };
    }

    const clientId = this.getClientIdentifier(request);
    const now = Date.now();
    const windowKey = `ratelimit:${clientId}:${Math.floor(now / RATE_LIMIT_WINDOW)}`;

    try {
      const currentCount = await this.env.RATE_LIMIT.get(windowKey);
      const count = currentCount ? parseInt(currentCount) : 0;

      if (count >= MAX_REQUESTS_PER_WINDOW) {
        return { allowed: false, remaining: 0 };
      }

      await this.env.RATE_LIMIT.put(windowKey, (count + 1).toString(), {
        expirationTtl: Math.ceil(RATE_LIMIT_WINDOW / 1000) * 2
      });

      return { allowed: true, remaining: MAX_REQUESTS_PER_WINDOW - count - 1 };
    } catch (error) {
      console.error('Rate limit check failed:', error);
      return { allowed: true, remaining: MAX_REQUESTS_PER_WINDOW };
    }
  }

  getClientIdentifier(request) {
    const cfConnectingIP = request.headers.get('CF-Connecting-IP');
    if (cfConnectingIP) return cfConnectingIP;
    
    const xForwardedFor = request.headers.get('X-Forwarded-For');
    if (xForwardedFor) return xForwardedFor.split(',')[0].trim();
    
    return 'unknown';
  }

  authenticateRequest(request) {
    const authHeader = request.headers.get('Authorization');
    
    if (!authHeader) {
      return { valid: false, error: 'Missing authorization header' };
    }

    const parts = authHeader.split(' ');
    if (parts.length !== 2 || parts[0] !== 'Bearer') {
      return { valid: false, error: 'Invalid authorization format' };
    }

    const token = parts[1];
    
    if (!this.apiSecretKey) {
      console.error('API_SECRET_KEY not configured');
      return { valid: false, error: 'Server configuration error' };
    }

    if (this.constantTimeCompare(token, this.apiSecretKey)) {
      return { valid: true };
    }

    return { valid: false, error: 'Invalid token' };
  }

  constantTimeCompare(a, b) {
    if (typeof a !== 'string' || typeof b !== 'string') {
      return false;
    }
    
    if (a.length !== b.length) {
      return false;
    }

    let result = 0;
    for (let i = 0; i < a.length; i++) {
      result |= a.charCodeAt(i) ^ b.charCodeAt(i);
    }
    return result === 0;
  }

  async handleSendEmail(request) {
    try {
      if (!this.sendgridApiKey) {
        return this.errorResponse('SendGrid not configured', 500);
      }

      const body = await this.parseAndValidateJSON(request);
      if (!body) {
        return this.errorResponse('Invalid JSON body', 400);
      }

      const { to, subject, text, html } = body;

      if (!this.validateEmail(to)) {
        return this.errorResponse('Invalid email address', 400);
      }

      if (!subject || typeof subject !== 'string' || subject.length > 200) {
        return this.errorResponse('Invalid subject', 400);
      }

      if ((!text && !html) || (text && typeof text !== 'string') || (html && typeof html !== 'string')) {
        return this.errorResponse('Invalid email content', 400);
      }

      if ((text && text.length > 50000) || (html && html.length > 100000)) {
        return this.errorResponse('Email content too large', 400);
      }

      const emailData = {
        personalizations: [{
          to: [{ email: this.sanitizeString(to) }]
        }],
        from: { email: this.env.SENDGRID_FROM_EMAIL || 'noreply@example.com' },
        subject: this.sanitizeString(subject),
        content: []
      };

      if (text) {
        emailData.content.push({
          type: 'text/plain',
          value: this.sanitizeString(text)
        });
      }

      if (html) {
        emailData.content.push({
          type: 'text/html',
          value: this.sanitizeString(html)
        });
      }

      const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.sendgridApiKey}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(emailData)
      });

      if (!response.ok) {
        const errorText = await response.text();
        console.error('SendGrid error:', response.status, errorText);
        return this.errorResponse('Failed to send email', 500);
      }

      return this.jsonResponse({ success: true, message: 'Email sent successfully' });
    } catch (error) {
      console.error('Send email error:', error);
      return this.errorResponse('Failed to send email', 500);
    }
  }

  async handleCreatePaymentIntent(request) {
    try {
      if (!this.stripeApiKey) {
        return this.errorResponse('Stripe not configured', 500);
      }

      const body = await this.parseAndValidateJSON(request);
      if (!body) {
        return this.errorResponse('Invalid JSON body', 400);
      }

      const { amount, currency, description, metadata } = body;

      if (!Number.isInteger(amount) || amount < 50 || amount > 99999999) {
        return this.errorResponse('Invalid amount', 400);
      }

      if (!currency || typeof currency !== 'string' || !/^[a-z]{3}$/.test(currency)) {
        return this.errorResponse('Invalid currency', 400);
      }

      const paymentData = new URLSearchParams({
        amount: amount.toString(),
        currency: currency.toLowerCase()
      });

      if (description && typeof description === 'string' && description.length <= 1000) {
        paymentData.append('description', this.sanitizeString(description));
      }

      if (metadata && typeof metadata === 'object') {
        const sanitizedMetadata = this.sanitizeMetadata(metadata);
        Object.entries(sanitizedMetadata).forEach(([key, value]) => {
          if (Object.keys(sanitizedMetadata).length <= 50) {
            paymentData.append(`metadata[${key}]`, value);
          }
        });
      }

      const response = await fetch('https://api.stripe.com/v1/payment_intents', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.stripeApiKey}`,
          'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: paymentData.toString()
      });

      const responseData = await response.json();

      if (!response.ok) {
        console.error('Stripe error:', response.status, responseData);
        return this.errorResponse(responseData.error?.message || 'Failed to create payment intent', response.status);
      }

      return this.jsonResponse({
        success: true,
        clientSecret: responseData.client_secret,
        paymentIntentId: responseData.id
      });
    } catch (error) {
      console.error('Create payment intent error:', error);
      return this.errorResponse('Failed to create payment intent', 500);
    }
  }

  async handleStripeWebhook(request) {
    try {
      if (!this.env.STRIPE_WEBHOOK_SECRET) {
        return this.errorResponse('Webhook not configured', 500);
      }

      const signature = request.headers.get('stripe-signature');
      if (!signature) {
        return this.errorResponse('Missing signature', 400);
      }

      const payload = await request.text();
      
      const verified = await this.verifyStripeSignature(payload, signature, this.env.STRIPE_WEBHOOK_SECRET);
      if (!verified) {
        return this.errorResponse('Invalid signature', 401);
      }

      const event = JSON.parse(payload);

      console.log('Stripe webhook event:', event.type, event.id);

      switch (event.type) {
        case 'payment_intent.succeeded':
          console.log('Payment succeeded:', event.data.object.id);
          break;
        case 'payment_intent.payment_failed':
          console.log('Payment failed:', event.data.object.id);
          break;
        default:
          console.log('Unhandled event type:', event.type);
      }

      return this.jsonResponse({ received: true });
    } catch (error) {
      console.error('Webhook error:', error);
      return this.errorResponse('Webhook processing failed', 500);
    }
  }

  async verifyStripeSignature(payload, signature, secret) {
    try {
      const elements = signature.split(',').reduce((acc, element) => {
        const [key, value] = element.split('=');
        if (key && value) acc[key] = value;
        return acc;
      }, {});

      const timestamp = elements.t;
      const signatures = [elements.v1];

      if (!timestamp || !signatures[0]) {
        return false;
      }

      const currentTime = Math.floor(Date.now() / 1000);
      if (Math.abs(currentTime - parseInt(timestamp)) > 300) {
        return false;
      }

      const signedPayload = `${timestamp}.${payload}`;
      const encoder = new TextEncoder();
      const key = await crypto.subtle.importKey(
        'raw',
        encoder.encode(secret),
        { name: 'HMAC', hash: 'SHA-256' },
        false,
        ['sign']
      );

      const signatureBuffer = await crypto.subtle.sign(
        'HMAC',
        key,
        encoder.encode(signedPayload)
      );

      const expectedSignature = Array.from(new Uint8Array(signatureBuffer))
        .map(b => b.toString(16).padStart(2, '0'))
        .join('');

      return this.constantTimeCompare(expectedSignature, signatures[0]);
    } catch (error) {
      console.error('Signature verification error:', error);
      return false;
    }
  }

  async parseAndValidateJSON(request) {
    try {
      const contentType = request.headers.get('Content-Type');
      if (!contentType || !contentType.includes('application/json')) {
        return null;
      }

      const text = await request.text();
      if (text.length > 1048576) {
        return null;
      }

      return JSON.parse(text);
    } catch (error) {
      return null;
    }
  }

  validateEmail(email) {
    if (typeof email !== 'string' || email.length > 254) {
      return false;
    }
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }

  sanitizeString(str) {
    if (typeof str !== 'string') return '';
    return str.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '');
  }

  sanitizeMetadata(metadata) {
    const sanitized = {};
    let count = 0;
    for (const [key, value] of Object.entries(metadata)) {
      if (count >= 50) break;
      if (typeof key === 'string' && key.length <= 40 && typeof value === 'string' && value.length <= 500) {
        sanitized[this.sanitizeString(key)] = this.sanitizeString(value);
        count++;
      }
    }
    return sanitized;
  }

  handleCORS(request) {
    const origin = request.headers.get('Origin');
    const headers = {
      'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization',
      'Access-Control-Max-Age': '86400'
    };

    if (this.validateOrigin(request) && origin) {
      headers['Access-Control-Allow-Origin'] = origin;
      headers['Vary'] = 'Origin';
    }

    return new Response(null, { status: 204, headers });
  }

  jsonResponse(data, status = 200, additionalHeaders = {}) {
    const headers = {
      'Content-Type': 'application/json',
      'X-Content-Type-Options': 'nosniff',
      'X-Frame-Options': 'DENY',
      'X-XSS-Protection': '1; mode=block',
      'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
      ...additionalHeaders
    };

    const origin = additionalHeaders.origin;
    if (origin && this.allowedOrigins.length > 0) {
      headers['Access-Control-Allow-Origin'] = origin;
      headers['Vary'] = 'Origin';
    }

    return new Response(JSON.stringify(data), { status, headers });
  }

  errorResponse(message, status = 400, additionalHeaders = {}) {
    return this.jsonResponse({ error: message }, status, additionalHeaders);
  }
}

export default {
  async fetch(request, env, ctx) {
    const worker = new APIIntegrationWorker(env);
    return await worker.handleRequest(request);
  }
};